// Helper: clean strings
function cleanStr(v) {
  if (!v) return '';
  return String(v).replace(/\s+/g, ' ').trim();
}

// Helper: safe array join
function joinArr(arr) {
  if (!Array.isArray(arr)) return '';
  return arr.map(a => cleanStr(a)).filter(Boolean).join(', ');
}

// 1) Normalize ClinicalTrials.gov
const ct_raw = [];
try {
  const ct_data = $('ClinicalTrials Agent').first();
  const studies = ct_data?.json?.studies || [];

  for (const s of studies) {
    const id       = s.protocolSection?.identificationModule || {};
    const status   = s.protocolSection?.statusModule || {};
    const sponsor  = s.protocolSection?.sponsorCollaboratorsModule || {};
    const design   = s.protocolSection?.designModule || {};
    const arms     = s.protocolSection?.armsInterventionsModule || {};
    const conds    = s.protocolSection?.conditionsModule || {};

    const nctId    = cleanStr(id.nctId);
    const title    = cleanStr(id.officialTitle || id.briefTitle);
    const phase    = joinArr(design.phases || []);
    const condStr  = joinArr(conds.conditions || []);
    const armName  = arms.interventions && arms.interventions[0]
      ? cleanStr(arms.interventions[0].name)
      : '';

    // Simple quality scoring (for later prioritization)
    let quality = 0;
    if (nctId) quality += 2;
    if (title) quality += 2;
    if (phase) quality += 1;
    if (condStr) quality += 1;
    if (status.overallStatus) quality += 1;

    ct_raw.push({
      source_id: nctId,
      source: 'clinicaltrials',
      title,
      sponsor: cleanStr(sponsor.leadSponsor?.name),
      drug_name: armName,
      indication: condStr,
      phase,
      status: cleanStr(status.overallStatus),
      url: nctId ? `https://clinicaltrials.gov/study/${nctId}` : '',
      raw_text: JSON.stringify(s).slice(0, 300), // shorter for Groq
      signal_origin: 'trial',
      quality_score: quality
    });
  }
} catch (e) {
  // optional: console.log('CT normalize error:', e.message);
}

// 2) Normalize PubMed
const pm_raw = [];
try {
  const pm_data = $('PubMed Agent').first();
  const ids = pm_data?.json?.esearchresult?.idlist || [];

  for (const pmid of ids) {
    const pmidStr = cleanStr(pmid);
    if (!pmidStr) continue;

    pm_raw.push({
      source_id: `pubmed_${pmidStr}`,
      source: 'pubmed',
      title: `PubMed Article ${pmidStr}`,
      sponsor: '',
      drug_name: '',
      indication: 'oncology',
      phase: '',
      status: '',
      url: `https://pubmed.ncbi.nlm.nih.gov/${pmidStr}/`,
      raw_text: `PMID: ${pmidStr}`,
      signal_origin: 'publication',
      quality_score: 1
    });
  }
} catch (e) {
  // optional: console.log('PM normalize error:', e.message);
}

// 3) Merge, filter, sort by quality, and optionally limit for rate control
let all_signals = [...ct_raw, ...pm_raw]
  .filter(s => !!s.source_id)
  .sort((a, b) => (b.quality_score || 0) - (a.quality_score || 0));

// TEMP: hard cap per run to protect Groq from rate limits
const HARD_CAP = 10;
all_signals = all_signals.slice(0, HARD_CAP);

return all_signals.map(s => ({ json: s }));

function cleanStr(v) {
  if (!v) return '';
  return String(v).replace(/\s+/g, ' ').trim();
}

function computeImpactLevel(baseSignal, ai) {
  const phase = cleanStr(baseSignal.phase).toUpperCase();
  const status = cleanStr(baseSignal.status).toUpperCase();
  const src = cleanStr(baseSignal.source).toLowerCase();
  const title = cleanStr(baseSignal.title).toLowerCase();
  const summary = cleanStr(ai.summary || '').toLowerCase();
  const sigType = cleanStr(ai.signal_type || '').toLowerCase();
  const competitor = ai.competitor_flag === true;

  let score = 0;

  // --- STRUCTURED FEATURES ---

  // Phase
  if (phase.includes('PHASE 3') || phase.includes('PHASE3')) score += 4;
  else if (phase.includes('PHASE 2') || phase.includes('PHASE2')) score += 2;
  else if (phase.includes('PHASE 1') || phase.includes('PHASE1')) score += 1;

  // Status
  if (status.includes('COMPLETED')) score += 3;
  if (status.includes('TERMINATED') || status.includes('SUSPENDED')) score += 4;
  if (status.includes('RECRUITING') || status.includes('ACTIVE')) score += 1;

  // Source
  if (src === 'pubmed') score += 1;

  // Competitor flag
  if (competitor) score += 2;

  // Signal type
  if (sigType === 'approval') score += 6;
  if (sigType === 'termination') score += 4;
  if (sigType === 'safety_signal') score += 5;
  if (sigType === 'label_expansion') score += 3;
  if (sigType === 'trial_update') score += 1;
  if (sigType === 'publication') score += 1;
  if (sigType === 'pipeline_entry') score += 1;

  // --- TEXTUAL KEYWORDS (title + summary) ---

  const text = `${title} ${summary}`;

  const highKeywords = [
    'fda approval',
    'approved',
    'pivotal',
    'overall survival',
    'primary endpoint met',
    'primary end point met',
    'breakthrough therapy',
    'regulatory submission',
    'submission accepted',
    'boxed warning',
    'black box warning',
    'discontinued due to safety',
    'dose-limiting toxicity'
  ];

  const medKeywords = [
    'phase ii',
    'phase 2',
    'randomized',
    'interim analysis',
    'objective response rate',
    'disease-free survival',
    'progression-free survival',
    'pfs',
    'dfs',
    'os result',
    'label update',
    'label change',
    'key opinion leader',
    'kol'
  ];

  const lowKeywords = [
    'phase i',
    'phase 1',
    'first-in-human',
    'case report',
    'retrospective',
    'exploratory'
  ];

  highKeywords.forEach(k => { if (text.includes(k)) score += 3; });
  medKeywords.forEach(k => { if (text.includes(k)) score += 1; });
  lowKeywords.forEach(k => { if (text.includes(k)) score += 0.5; });

  // --- SAFETY & TERMINATION OVERRIDES ---

  if (
    text.includes('serious adverse event') ||
    text.includes('dose-limiting toxicity') ||
    text.includes('unexpected safety') ||
    status.includes('TERMINATED') ||
    sigType === 'safety_signal'
  ) {
    score += 4;
  }

  // --- IMPACT BANDING ---

  let impact = 'LOW';

  if (score >= 9) impact = 'HIGH';
  else if (score >= 4) impact = 'MED';
  else impact = 'LOW';

  return { impact_level: impact, impact_score: score };
}

const out = [];

for (const item of $input.all()) {
  try {
    const raw = item.json.content || item.json.choices?.[0]?.message?.content || '{}';

    let clean = String(raw)
      .replace(/```json/gi, '')
      .replace(/```/g, '')
      .trim();

    const match = clean.match(/\{[\s\S]*\}/);
    if (match) clean = match[0];

    const ai = JSON.parse(clean);

    const baseSignal = {
      source_id: item.json.source_id,
      source: item.json.source,
      title: item.json.title,
      sponsor: item.json.sponsor,
      drug_name: item.json.drug_name,
      indication: item.json.indication,
      phase: item.json.phase,
      status: item.json.status,
      url: item.json.url,
      raw_text: item.json.raw_text,
      signal_origin: item.json.signal_origin,
      quality_score: item.json.quality_score
    };

    const { impact_level, impact_score } = computeImpactLevel(baseSignal, ai);

    out.push({
      json: {
        ...baseSignal,

        signal_type: ai.signal_type || 'unknown',
        impact_level,
        impact_score,
        competitor_flag: ai.competitor_flag === true,
        ai_summary: ai.summary || 'No summary',
        recommended_action: ai.recommended_action || 'Manual review',
        key_drug: ai.key_drug || baseSignal.drug_name || '',
        key_indication: ai.key_indication || baseSignal.indication || '',
        urgency: ai.urgency || 'monitor',
        confidence: ai.confidence || 'low',
        ai_processed: true,
        parse_error: null
      }
    });

  } catch (e) {
    out.push({
      json: {
        source_id: item.json.source_id,
        source: item.json.source,
        title: item.json.title,
        sponsor: item.json.sponsor || '',
        drug_name: item.json.drug_name || '',
        indication: item.json.indication || '',
        phase: item.json.phase || '',
        status: item.json.status || '',
        url: item.json.url || '',
        raw_text: item.json.raw_text || '',
        signal_origin: item.json.signal_origin,
        quality_score: item.json.quality_score,

        signal_type: 'unknown',
        impact_level: 'LOW',
        impact_score: 0,
        competitor_flag: false,
        ai_summary: 'Parse failed — manual review needed',
        recommended_action: 'Review this signal manually',
        key_drug: item.json.drug_name || '',
        key_indication: item.json.indication || 'oncology',
        urgency: 'monitor',
        confidence: 'low',
        ai_processed: false,
        parse_error: e.message
      }
    });
  }
}

return out;

