// Configuration
const CONFIG = {
  // which impact levels to route
  enabledLevels: ['HIGH', 'MED', 'LOW'],
  // maximum alerts per level per run (0 = no limit)
  maxPerLevel: {
    HIGH: 10,
    MED: 20,
    LOW: 20,
  },
  // minimum impact_score to send (per level), if present
  minScore: {
    HIGH: 0,
    MED: 0,
    LOW: 0,
  }
};

function normImpact(v) {
  if (!v && v !== 0) return 'LOW';
  return String(v).toUpperCase().replace(/^=+/, '').trim();
}

function getScore(item) {
  const s = item.json?.impact_score;
  const n = Number(s);
  return Number.isFinite(n) ? n : 0;
}

const buckets = {
  HIGH: [],
  MED: [],
  LOW: [],
};

// 1) Bucket items by normalized impact level
for (const item of $input.all()) {
  const impact = normImpact(item.json.impact_level);
  const score = getScore(item);

  // Default unknown impacts to LOW
  let level = 'LOW';
  if (impact === 'HIGH') level = 'HIGH';
  else if (impact === 'MED') level = 'MED';

  // Filter by enabledLevels
  if (!CONFIG.enabledLevels.includes(level)) continue;

  // Filter by minScore per level
  if (score < (CONFIG.minScore[level] || 0)) continue;

  buckets[level].push({ item, score });
}

// 2) Sort each bucket by score (desc) and apply maxPerLevel
const routed = {};
for (const level of ['HIGH', 'MED', 'LOW']) {
  let arr = buckets[level];

  // sort: highest score first
  arr.sort((a, b) => b.score - a.score);

  const maxN = CONFIG.maxPerLevel[level] || 0;
  if (maxN > 0) {
    arr = arr.slice(0, maxN);
  }

  routed[level] = arr.map(({ item }) => item.json);
}

// 3) Build a single routing summary object
const result = {
  high_signals: routed.HIGH,
  med_signals: routed.MED,
  low_signals: routed.LOW,
  stats: {
    total_input: $input.all().length,
    total_high: routed.HIGH.length,
    total_med: routed.MED.length,
    total_low: routed.LOW.length,
    timestamp: new Date().toISOString(),
  }
};

return [{ json: result }];

// Config for HIGH alerts
const CONFIG = {
  maxHighPerRun: 10,         // hard cap per execution (0 = no cap)
  sortByScoreDesc: true,     // use impact_score if available
  dedupBySourceId: true      // avoid duplicate source_id in this batch
};

function getScore(obj) {
  const n = Number(obj.impact_score);
  return Number.isFinite(n) ? n : 0;
}

const input = $input.first().json;
let highs = Array.isArray(input.high_signals) ? input.high_signals : [];

// 1) Optional dedup by source_id
if (CONFIG.dedupBySourceId) {
  const seen = new Set();
  highs = highs.filter(h => {
    const id = h.source_id || '';
    if (!id) return true;
    if (seen.has(id)) return false;
    seen.add(id);
    return true;
  });
}

// 2) Sort by impact_score desc if configured
if (CONFIG.sortByScoreDesc) {
  highs.sort((a, b) => getScore(b) - getScore(a));
}

// 3) Apply max per run
if (CONFIG.maxHighPerRun > 0) {
  highs = highs.slice(0, CONFIG.maxHighPerRun);
}

// 4) Add alert metadata to each item
const now = new Date().toISOString();
const out = highs.map((h, index) => ({
  json: {
    ...h,
    alert_meta: {
      level: 'HIGH',
      rank_in_batch: index + 1,
      batch_size: highs.length,
      routed_at: now
    }
  }
}));

return out;

// Config for MED alerts
const CONFIG = {
  maxMedPerRun: 20,          // hard cap per execution (0 = no cap)
  sortByScoreDesc: true,
  dedupBySourceId: true
};

function getScore(obj) {
  const n = Number(obj.impact_score);
  return Number.isFinite(n) ? n : 0;
}

const input = $input.first().json;
let meds = Array.isArray(input.med_signals) ? input.med_signals : [];

// 1) Optional dedup by source_id
if (CONFIG.dedupBySourceId) {
  const seen = new Set();
  meds = meds.filter(m => {
    const id = m.source_id || '';
    if (!id) return true;
    if (seen.has(id)) return false;
    seen.add(id);
    return true;
  });
}

// 2) Sort by impact_score desc if configured
if (CONFIG.sortByScoreDesc) {
  meds.sort((a, b) => getScore(b) - getScore(a));
}

// 3) Apply max per run
if (CONFIG.maxMedPerRun > 0) {
  meds = meds.slice(0, CONFIG.maxMedPerRun);
}

// 4) Add alert metadata
const now = new Date().toISOString();
const out = meds.map((m, index) => ({
  json: {
    ...m,
    alert_meta: {
      level: 'MED',
      rank_in_batch: index + 1,
      batch_size: meds.length,
      routed_at: now
    }
  }
}));

return out;

// Config for LOW alerts
const CONFIG = {
  maxLowPerRun: 20,          // hard cap per execution (0 = no cap)
  sortByScoreDesc: true,
