}

const input = $input.first().json;
let lows = Array.isArray(input.low_signals) ? input.low_signals : [];

// 1) Optional dedup by source_id
if (CONFIG.dedupBySourceId) {
  const seen = new Set();
  lows = lows.filter(l => {
