// Check execution mode: 'test' when you click Execute, 'production' when auto-run [web:7][web:4]
const mode = $execution.mode;  // or $execution.mode in expression view

// We only want to trigger digest on MANUAL / TEST runs.
const shouldTrigger = mode === 'test';

// Expose flag to next node
return [
  {
    json: {
      shouldTrigger,
      mode
    }
  }
];

const items = $input.all();

// ─── SCORING WEIGHTS v1.0 ─────────────────────────────────
const WEIGHTS = {
  // Base impact level scores
  baseScore: {
    HIGH: 6.0,
    MED:  3.5,
    LOW:  1.0,
    UNKNOWN: 0.5
  },

  // Signal type weights
  signalType: {
    'fda_approval'       : 2.0,
    'approval'           : 2.0,
    'regulatory'         : 1.8,
    'safety_update'      : 1.7,
    'trial_result'       : 1.5,
    'phase3_result'      : 1.8,
    'phase2_result'      : 1.3,
    'phase1_result'      : 0.8,
    'trial_update'       : 0.8,
    'publication'        : 0.7,
    'press_release'      : 0.5,
    'conference'         : 0.5,
    'acquisition'        : 1.2,
    'merger'             : 1.2,
    'partnership'        : 0.6,
    'patent'             : 0.4,
    'ipo'                : 0.6,
    'funding'            : 0.5,
