    'orphan_designation' : 0.8,
    'trial_initiation'   : 0.6,
    'biomarker'          : 0.9,
    'combo_therapy'      : 1.1
  },

  // Competitor bonus
  competitor: 2.5,

  // Source credibility weights
  source: {
    'clinicaltrials'     : 1.0,
    'fda'                : 1.2,
    'ema'                : 1.1,
    'pubmed'             : 0.9,
    'sec'                : 0.8,
    'press'              : 0.6,
    'twitter'            : 0.4,
    'news'               : 0.5,
    'company_website'    : 0.7,
    'conference'         : 0.8
  },

  // Version activity bonus
  version: {
    v2:    0.3,
    v3:    0.5,
    v4plus: 0.8
  },

  // Recency bonus (hours since first_seen)
  recency: {
    within6h:  1.0,
    within24h: 0.5,
    within48h: 0.2,
    older:     0.0
  },

  // Indication strategic importance for Novartis oncology
  indication: {
    'non-small cell lung carcinoma'    : 1.5,
    'nsclc'                            : 1.5,
    'breast carcinoma'                 : 1.3,
    'triple-negative breast carcinoma' : 1.5,
    'tnbc'                             : 1.5,
    'colorectal carcinoma'             : 1.2,
    'melanoma'                         : 1.2,
    'renal cell carcinoma'             : 1.1,
    'clear cell renal carcinoma'       : 1.2,
    'hepatocellular carcinoma'         : 1.1,
    'ovarian carcinoma'                : 1.2,
    'bladder carcinoma'                : 1.0,
    'prostate carcinoma'               : 1.1,
    'leukemia'                         : 1.2,
    'lymphoma'                         : 1.1,
    'multiple myeloma'                 : 1.2,
    'glioblastoma'                     : 1.3,
    'pancreatic carcinoma'             : 1.2,
    'gastric carcinoma'                : 1.0,
    'cervical carcinoma'               : 1.0
  },

  // Maximum possible score cap
  MAX_SCORE: 10.0
};

// ─── HELPER FUNCTIONS ─────────────────────────────────────

function getBaseScore(impact_level) {
  const level = String(impact_level || '').toUpperCase();
  return WEIGHTS.baseScore[level] || WEIGHTS.baseScore.UNKNOWN;
}

function getSignalTypeBonus(signal_type) {
  const type = String(signal_type || '').toLowerCase().replace(/[\s-]/g, '_');
  return WEIGHTS.signalType[type] || 0;
}

function getCompetitorBonus(competitor_flag) {
  return (competitor_flag === true || competitor_flag === 'true') ? WEIGHTS.competitor : 0;
}

function getSourceBonus(source) {
  const src = String(source || '').toLowerCase().trim();
  for (const [key, val] of Object.entries(WEIGHTS.source)) {
    if (src.includes(key)) return val;
  }
  return 0.5;
}

function getVersionBonus(version) {
  const v = parseInt(version || 1, 10);
  if (v >= 4)      return WEIGHTS.version.v4plus;
  else if (v === 3) return WEIGHTS.version.v3;
  else if (v === 2) return WEIGHTS.version.v2;
  return 0;
}

function getRecencyBonus(first_seen_at) {
  try {
    const hoursAgo = (Date.now() - new Date(first_seen_at).getTime()) / 3600000;
    if (hoursAgo <= 6)  return WEIGHTS.recency.within6h;
    if (hoursAgo <= 24) return WEIGHTS.recency.within24h;
    if (hoursAgo <= 48) return WEIGHTS.recency.within48h;
    return WEIGHTS.recency.older;
  } catch(e) {
    return 0;
  }
}

function getIndicationBonus(key_indication) {
  const ind = String(key_indication || '').toLowerCase().trim();
  for (const [key, val] of Object.entries(WEIGHTS.indication)) {
    if (ind.includes(key)) return val;
  }
  return 0;
}

function getUrgencyFlag(level, competitor, signalType, score) {
  const type = String(signalType || '').toLowerCase();
  const isCriticalType = [
    'fda_approval', 'approval', 'safety_update',
    'regulatory', 'label_update', 'breakthrough_designation'
  ].some(t => type.includes(t));

  return (
    (level === 'HIGH' && competitor) ||
    (score >= 8.5) ||
    (level === 'HIGH' && isCriticalType) ||
    (competitor && isCriticalType)
  );
}

// ─── MAIN SCORING LOOP ────────────────────────────────────
return items.map(item => {
  const s = { ...item.json };

  const level       = String(s.impact_level || '').toUpperCase();
  const isCompetitor = s.competitor_flag === true || String(s.competitor_flag) === 'true';

  // Calculate each component
  const baseScore        = getBaseScore(s.impact_level);
  const signalTypeBonus  = getSignalTypeBonus(s.signal_type);
  const competitorBonus  = getCompetitorBonus(s.competitor_flag);
  const sourceBonus      = getSourceBonus(s.source);
  const versionBonus     = getVersionBonus(s.version);
  const recencyBonus     = getRecencyBonus(s.first_seen_at);
  const indicationBonus  = getIndicationBonus(s.key_indication);

  // Raw score
  const rawScore = (
    baseScore +
    signalTypeBonus +
    competitorBonus +
    sourceBonus +
    versionBonus +
    recencyBonus +
    indicationBonus
  );

  // Cap at MAX_SCORE
  const finalScore = Math.min(
    parseFloat(rawScore.toFixed(2)),
    WEIGHTS.MAX_SCORE
  );

  // Urgency flag
  const isUrgent = getUrgencyFlag(level, isCompetitor, s.signal_type, finalScore);

  // Full breakdown for audit trail
  const scoreBreakdown = {
    base:        baseScore,
    signalType:  signalTypeBonus,
    competitor:  competitorBonus,
    source:      sourceBonus,
    version:     versionBonus,
    recency:     recencyBonus,
    indication:  indicationBonus,
    raw:         parseFloat(rawScore.toFixed(2)),
    final:       finalScore,
    scoringVersion: 1
  };

  return {
    json: {
      ...s,
      impact_score:     finalScore,
      is_urgent:        isUrgent,
      score_breakdown:  JSON.stringify(scoreBreakdown),
      scoring_version:  1
    }
  };
});
